frappe.ui.form.on('Disciplinary', {
    // ===== AUTO-POPULATE WARNING LEVEL =====
    employee(frm) {
        if (!frm.doc.employee) return;

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Disciplinary",
                filters: { 
                    employee: frm.doc.employee,
                    docstatus: 1
                },
                fields: ["warning_level"]
            },
            callback(r) {
                let count = r.message ? r.message.length : 0;

                let next_level = "First Warning";
                if (count === 1) next_level = "Second Warning";
                else if (count === 2) next_level = "Final Warning";
                else if (count >= 3) next_level = "Summary Dismissal";

                frm.set_value("warning_level", next_level);
            }
        });
    },

    // ===== GROSS MISCONDUCT CHECKBOX =====
    custom_is_gross_misconduct(frm) {
        if (frm.doc.custom_is_gross_misconduct) {
            frm.set_value("warning_level", "Summary Dismissal");
        }
    },

    // ===== DYNAMIC BUTTONS BASED ON WARNING LEVEL =====
    refresh(frm) {
        // Clear existing custom buttons
        frm.page.clear_menu();

        if (frm.doc.docstatus === 1) {
            let warning_level = frm.doc.warning_level;

            // ===== SUMMARY DISMISSAL: Only Summary Dismissal button =====
            if (warning_level === "Summary Dismissal") {
                frm.add_custom_button('Download Summary Dismissal', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Summary Dismissal Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');
            }

            // ===== FINAL WARNING: Two buttons (Warning Letter + Summary Dismissal) =====
            else if (warning_level === "Final Warning") {
                frm.add_custom_button('Download Warning Letter', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Disciplinary Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');

                frm.add_custom_button('Download Summary Dismissal', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Summary Dismissal Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');
            }

            // ===== OTHER WARNINGS: Standard Warning Letter button =====
            else {
                frm.add_custom_button('Download Warning Letter', () => {
                    let url = frappe.urllib.get_full_url(
                        `/api/method/frappe.utils.print_format.download_pdf?`
                        + `doctype=${encodeURIComponent(frm.doctype)}`
                        + `&name=${encodeURIComponent(frm.docname)}`
                        + `&format=Disciplianry Letter`
                        + `&no_letterhead=0`
                    );
                    window.open(url);
                }, 'fa fa-file-pdf');
            }
        }
    }
});

frappe.ui.form.on('Employee', {
    onload: function(frm) {
        if (frm.is_new() && !frm.doc.employee_number) {
            frm.set_value('employee_number', 'Generating...');
            frappe.call({
                method: 'frappe.client.get_list',
                args: {
                    doctype: 'Employee',
                    fields: ['employee_number'],
                    filters: [
                        ['employee_number', 'is', 'set'],
                        ['employee_number', '!=', '']
                    ],
                    limit_page_length: 1000
                },
                callback: function(r) {
                    let nextNumber = 1;
                    if (r.message && r.message.length > 0) {
                        // Extract numeric part only, ignoring any prefix (like PK)
                        const numbers = r.message.map(e => {
                            const match = e.employee_number.match(/\d+/);
                            return match ? parseInt(match[0]) : 0;
                        });
                        const maxNum = Math.max(...numbers);
                        if (!isNaN(maxNum)) {
                            nextNumber = maxNum + 1;
                        }
                    }
                    // ✅ Add PK prefix to the number
                    frm.set_value('employee_number', 'PK' + nextNumber.toString());
                    console.log("Generated employee number:", 'PK' + nextNumber);
                }
            });
        }
    }
});

